<div class="clearfix"><h3 class="pull-left"><?= $isDocente ? 'Mis asignaciones' : 'Asignaciones por docente' ?></h3><?php if (!$isDocente): ?><a class="btn btn-primary pull-right" href="<?= BASE_URL ?>/index.php?c=AsignacionesDocente&a=create">Nuevo</a><?php endif; ?></div><hr>
<table class="table table-bordered table-striped"><thead><tr><th>ID</th><th>Asignación</th><?php if (!$isDocente): ?><th>Docente</th><th></th><?php endif; ?></tr></thead><tbody>
<?php foreach ($rows as $r): ?><tr><td><?= (int)$r['id'] ?></td><td><?= htmlspecialchars((string)($r['asignacion_nombre'] ?? '')) ?></td><?php if (!$isDocente): ?><td><?= htmlspecialchars((string)($r['docente_nombre'] ?? '').' '.($r['docente_apellido'] ?? '')) ?></td><td><a class="btn btn-xs btn-info" href="<?= BASE_URL ?>/index.php?c=AsignacionesDocente&a=edit&id=<?= (int)$r['id'] ?>">Editar</a> <a class="btn btn-xs btn-danger" onclick="return confirm('¿Eliminar?');" href="<?= BASE_URL ?>/index.php?c=AsignacionesDocente&a=delete&id=<?= (int)$r['id'] ?>">Eliminar</a></td><?php endif; ?></tr><?php endforeach; ?>
<?php if (!$rows): ?><tr><td colspan="<?= $isDocente ? 2 : 4 ?>">Sin registros.</td></tr><?php endif; ?></tbody></table>
